import React from "react";
import FeatureDetail from "./FeatureDetail";

const pageData = {
  title: "Confidential Computing",
  subtitle: "Hardware-secured enclaves for protected data processing",
  description: "Process your most sensitive data in hardware-secured enclaves. Our confidential computing platform ensures that data remains encrypted during processing, protecting it from insider threats, firmware attacks, and cloud provider access. Support for Intel SGX, AMD SEV, and ARM TrustZone.",
  benefits: [
    "Hardware-secured enclaves (SGX, SEV, TrustZone)",
    "Data encrypted during entire processing lifecycle",
    "Protection from insider threats and privileged access",
    "Secure multi-party computation capabilities",
    "Cloud-agnostic deployment across providers"
  ],
  features: [
    { title: "Secure Enclaves", description: "Hardware-based trusted execution environments" },
    { title: "Data-in-Use Protection", description: "Encryption maintained during computation" },
    { title: "Attestation", description: "Remote verification of enclave integrity" },
    { title: "Key Management", description: "Secure key provisioning to enclaves" },
    { title: "Multi-Party Compute", description: "Process data from multiple parties without exposure" }
  ],
  howItWorks: [
    { title: "Enclave Creation", description: "A secure enclave is created in hardware" },
    { title: "Attestation", description: "Remote parties verify the enclave's integrity" },
    { title: "Secure Processing", description: "Data is processed encrypted within the enclave" },
    { title: "Result Delivery", description: "Results are securely delivered to authorized parties" }
  ],
  color: "#3b82f6",
  icon: "M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4",
  gradient: "from-blue-500 to-indigo-600"
};

function ConfidentialComputing() {
  return <FeatureDetail {...pageData} />;
}

export default ConfidentialComputing;
